/* ============================================================
   Buttons
   ============================================================ */
.btn{
  display:inline-flex; align-items:center; gap:9px;
  padding:13px 22px; border-radius:999px;
  font-family:var(--font-disp); font-weight:600; font-size:.95rem; letter-spacing:.01em;
  background:var(--grad); color:#04130f;
  transition:transform .25s var(--ease), box-shadow .25s var(--ease), filter .25s;
  box-shadow:0 10px 30px -12px rgba(27,186,152,.7); white-space:nowrap;
}
.btn .ic{ font-size:1.05em; stroke-width:2; }
.btn:hover{ transform:translateY(-2px); box-shadow:0 16px 36px -12px rgba(27,186,152,.85); filter:brightness(1.05); }
.btn--sm{ padding:10px 17px; font-size:.86rem; }
.btn--lg{ padding:16px 28px; font-size:1.02rem; }
.btn--block{ display:flex; width:100%; justify-content:center; margin-top:auto; }
.btn--ghost{ background:transparent; color:var(--text); border:1px solid var(--line); box-shadow:none; }
.btn--ghost:hover{ border-color:var(--acc); background:rgba(27,186,152,.08); box-shadow:var(--glow); }

/* ============================================================
   Hero
   ============================================================ */
.hero{ position:relative; padding:140px 0 90px; min-height:100vh; display:flex; align-items:center; }
.hero__inner{ display:grid; grid-template-columns:1.15fr .85fr; gap:50px; align-items:center; width:min(100% - 40px, var(--container)); }
.hero__title{
  font-family:var(--font-disp); font-weight:700;
  font-size:clamp(2.6rem, 6vw, 5rem); line-height:1.02; letter-spacing:-.025em;
  margin:22px 0 20px; text-wrap:balance;
}
.hero__title .grad{ display:block; }
.hero__lead{ font-size:clamp(1rem,1.4vw,1.2rem); color:var(--text-2); max-width:560px; }
.hero__actions{ display:flex; flex-wrap:wrap; gap:14px; margin:32px 0 44px; }

.hero__stats{ display:grid; grid-template-columns:repeat(4,1fr); gap:14px; max-width:600px; }
.hero__stats li{ display:flex; flex-direction:column; gap:3px; padding-left:16px; border-left:2px solid var(--line); }
.hero__stats b{ font-family:var(--font-disp); font-weight:700; font-size:clamp(1.6rem,2.6vw,2.3rem); line-height:1; }
.hero__stats span{ font-size:.82rem; color:var(--text-3); }

/* hero orb visual */
.hero__visual{ display:grid; place-items:center; }
.orb{ position:relative; width:min(420px,80vw); aspect-ratio:1; display:grid; place-items:center; }
.orb__ring-wrap{ position:relative; width:100%; aspect-ratio:1; display:grid; place-items:center; }
.orb__ring{ position:absolute; inset:0; border-radius:50%; border:1px solid var(--line); }
.orb__ring--1{ inset:0;  border-color:rgba(27,186,152,.28); animation:spin 26s linear infinite; }
.orb__ring--2{ inset:16%; border-color:rgba(30,214,175,.22); border-style:dashed; animation:spin 18s linear infinite reverse; }
.orb__ring--3{ inset:33%; border-color:rgba(0,212,167,.4); animation:spin 12s linear infinite; }
.orb__ring--1::before,.orb__ring--3::before{ content:""; position:absolute; top:-5px; left:50%; width:9px; height:9px; border-radius:50%; background:var(--acc-3); box-shadow:0 0 16px 3px var(--acc-2); }
@keyframes spin{ to{ transform:rotate(360deg); } }
.orb__core{
  position:relative; width:48%; aspect-ratio:1; border-radius:50%;
  display:grid; place-content:center; justify-items:center; text-align:center;
  background:radial-gradient(circle at 35% 30%, rgba(27,186,152,.35), rgba(10,11,13,.4) 70%);
  border:1px solid var(--line); backdrop-filter:blur(4px);
  box-shadow:inset 0 0 40px rgba(27,186,152,.25), var(--glow);
  animation:orbFloat 6s cubic-bezier(.45,.05,.55,.95) infinite;
}
@keyframes orbFloat{
  0%,100%{ transform:translateY(0) scale(1);     box-shadow:inset 0 0 40px rgba(27,186,152,.25), var(--glow); }
  40%{     transform:translateY(-10px) scale(1.022); box-shadow:inset 0 0 52px rgba(27,186,152,.38), 0 0 55px -6px rgba(27,186,152,.6); }
  60%{     transform:translateY(-8px) scale(1.018); }
}
.orb__num{ font-family:var(--font-disp); font-weight:700; font-size:clamp(1.8rem,4vw,2.6rem); letter-spacing:-.02em; }
.orb__num i{ font-style:normal; display:inline-block; margin-right:0.04em; }
.orb__label{ font-size:.62rem; letter-spacing:.4em; text-transform:uppercase; color:var(--acc-3); }
.orb__chip{
  position:absolute; display:inline-flex; align-items:center; gap:6px;
  padding:8px 13px; border-radius:999px; font-size:.8rem; font-weight:600;
  background:rgba(16,18,22,.85); border:1px solid var(--line); backdrop-filter:blur(8px);
  box-shadow:var(--shadow); white-space:nowrap;
}
.orb__chip .ic{ color:var(--acc-3); font-size:1.05em; }
.orb__chip--a{ top:6%;  left:-6%;  animation:float 5s var(--ease) infinite; }
.orb__chip--b{ top:44%; right:-12%; animation:float 6s var(--ease) infinite .6s; }
.orb__chip--c{ bottom:6%; left:8%;  animation:float 5.5s var(--ease) infinite 1.1s; }
.orb__chip--d{ top:20%; right:-8%; animation:float 5.2s var(--ease) infinite 1.8s; }
.orb__chip--e{ bottom:18%; right:2%; animation:float 6.4s var(--ease) infinite .3s; }
.orb__chip--f{ top:62%; left:-14%; animation:float 4.8s var(--ease) infinite 2.2s; }
@keyframes float{ 0%,100%{ transform:translateY(0);} 50%{ transform:translateY(-12px);} }

.hero__scroll{ position:absolute; bottom:26px; left:50%; transform:translateX(-50%); width:26px; height:42px; border:2px solid var(--line); border-radius:14px; display:grid; justify-items:center; padding-top:7px; }
.hero__scroll span{ width:4px; height:8px; border-radius:3px; background:var(--acc-3); animation:scrolldot 1.8s var(--ease) infinite; }
@keyframes scrolldot{ 0%{ opacity:0; transform:translateY(-4px);} 40%{opacity:1;} 80%,100%{ opacity:0; transform:translateY(12px);} }

/* ============================================================
   Marquee
   ============================================================ */
.marquee{ border-block:1px solid var(--line-2); padding:20px 0; overflow:hidden; background:linear-gradient(var(--bg-2),var(--bg-2)); -webkit-mask-image:linear-gradient(90deg,transparent,#000 8%,#000 92%,transparent); mask-image:linear-gradient(90deg,transparent,#000 8%,#000 92%,transparent); }
.marquee__track{ display:inline-flex; align-items:center; gap:26px; white-space:nowrap; animation:marquee 32s linear infinite; }
.marquee__track span{ font-family:var(--font-disp); font-weight:600; font-size:1.25rem; color:var(--text-2); }
.marquee__track i{ color:var(--acc); font-style:normal; }
.marquee:hover .marquee__track{ animation-play-state:paused; }
@keyframes marquee{ to{ transform:translateX(-50%);} }

/* ============================================================
   Sections generic
   ============================================================ */
.section{ padding:clamp(70px,9vw,120px) 0; position:relative; }
.section__head{ max-width:640px; margin-bottom:54px; }
.section__title{ font-family:var(--font-disp); font-weight:700; font-size:clamp(2rem,4.4vw,3.4rem); line-height:1.05; letter-spacing:-.025em; margin:16px 0 16px; }
.section__sub{ color:var(--text-2); font-size:1.05rem; max-width:560px; }

/* ============================================================
   Zones
   ============================================================ */
.zones{ display:grid; grid-template-columns:repeat(4,1fr); gap:18px; }
.zone{
  grid-column:span 2;
  position:relative; padding:26px; border-radius:var(--radius-lg);
  background:linear-gradient(180deg, var(--surface), var(--bg-2));
  border:1px solid var(--line-2); overflow:hidden;
  transition:transform .4s var(--ease), border-color .4s, box-shadow .4s;
  transform-style:preserve-3d;
}
.zone::before{ content:""; position:absolute; inset:0; border-radius:inherit; padding:1px; background:var(--grad); -webkit-mask:linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0); -webkit-mask-composite:xor; mask-composite:exclude; opacity:0; transition:opacity .4s; pointer-events:none; }
.zone::after{ content:""; position:absolute; width:280px; height:280px; border-radius:50%; top:-120px; right:-120px; background:radial-gradient(circle, rgba(27,186,152,.22), transparent 70%); opacity:0; transition:opacity .4s; pointer-events:none; }
.zone:hover{ transform:translateY(-6px); box-shadow:var(--shadow); }
.zone:hover::before{ opacity:1; }
.zone:hover::after{ opacity:1; }

.zone__top{ display:flex; align-items:center; justify-content:space-between; margin-bottom:10px; }
.zone__index{ font-family:var(--font-disp); font-weight:700; font-size:1.1rem; color:var(--text-3); }
.zone__badge{ display:inline-flex; align-items:center; gap:6px; padding:6px 12px; border-radius:999px; font-size:.74rem; font-weight:700; letter-spacing:.04em; color:var(--acc-3); background:rgba(27,186,152,.1); border:1px solid var(--line); }
.zone__badge--hot{ color:#04130f; background:var(--grad); border-color:transparent; }
.zone__badge .ic{ font-size:.95em; }
.zone__name{ font-family:var(--font-disp); font-weight:700; font-size:1.9rem; letter-spacing:-.02em; }
.zone__tag{ color:var(--text-3); font-size:.9rem; margin-bottom:18px; }

.specs{ display:grid; gap:2px; }
.specs li{ display:grid; grid-template-columns:auto 104px 1fr; align-items:center; gap:12px; padding:9px 0; border-top:1px solid var(--line-2); font-size:.92rem; }
.specs li:first-child{ border-top:none; }
.specs .ic{ font-size:1.15rem; color:var(--acc); }
.specs__k{ color:var(--text-3); font-size:.78rem; text-transform:uppercase; letter-spacing:.06em; }
.specs__v{ font-weight:600; }
.zone__note{ margin-top:16px; padding-top:14px; border-top:1px solid var(--line-2); color:var(--text-2); font-size:.9rem; }

/* Zone games list (PS5 block) */
.zone__games{ margin-top:16px; padding-top:14px; border-top:1px solid var(--line-2); }
.zone__games-label{ display:block; font-size:.65rem; letter-spacing:.35em; text-transform:uppercase; color:var(--text-3); margin-bottom:10px; }
.zone__games-list{ list-style:none; display:flex; flex-direction:column; gap:6px; }
.zone__game{
  display:flex; align-items:center; gap:10px;
  padding:8px 12px;
  border-radius:10px;
  background:rgba(255,255,255,.03);
  border:1px solid var(--line-2);
  transition:background .2s, border-color .2s;
}
.zone__game:hover{ background:rgba(27,186,152,.07); border-color:rgba(27,186,152,.25); }
.zone__game-num{ font-size:.62rem; font-weight:700; color:var(--text-3); letter-spacing:.08em; min-width:18px; }
.zone__game-name{ font-size:.9rem; font-weight:700; color:var(--text); flex:1; }
.zone__game-tag{ font-size:.62rem; font-weight:600; letter-spacing:.06em; text-transform:uppercase; padding:2px 8px; border-radius:999px; }
.zone__game--fc .zone__game-tag{ color:#4ade80; background:rgba(74,222,128,.12); }
.zone__game--ufc .zone__game-tag{ color:#f97316; background:rgba(249,115,22,.12); }
.zone__game--mk .zone__game-tag{ color:#a78bfa; background:rgba(167,139,250,.12); }

.zone--flagship{ background:linear-gradient(180deg, #0f1a18, var(--bg-2)); border-color:var(--line); }
.zone--flagship::after{ opacity:.6; }
.zone--ps{ background:linear-gradient(180deg, #0d1620, var(--bg-2)); }

/* ============================================================
   Tech
   ============================================================ */
.section--tech{ background:linear-gradient(var(--bg-2),var(--bg)); }
.tech{ display:grid; grid-template-columns:repeat(4,1fr); gap:18px; }
.tech__card{
  grid-column:span 2; position:relative; overflow:hidden;
  padding:30px; border-radius:var(--radius-lg);
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s, box-shadow .4s;
}
.tech__card--wide{ grid-column:span 2; }
.tech__card:hover{ transform:translateY(-6px); border-color:var(--line); box-shadow:var(--shadow); }
.tech__ic{ width:38px; height:38px; fill:none; stroke:var(--acc); stroke-width:1.6; margin-bottom:18px; filter:drop-shadow(0 0 10px rgba(27,186,152,.5)); }
.tech__card h3{ font-family:var(--font-disp); font-weight:700; font-size:1.45rem; letter-spacing:-.02em; margin-bottom:10px; }
.tech__card h3.tech__h--long{ font-size:1.18rem; letter-spacing:-.01em; }
.tech__card p{ color:var(--text-2); font-size:.95rem; }
.tech__pill{ display:inline-block; margin-top:18px; padding:5px 12px; border-radius:999px; font-size:.72rem; font-weight:700; text-transform:uppercase; letter-spacing:.08em; color:var(--acc-3); background:rgba(27,186,152,.1); border:1px solid var(--line); }

/* make grid nicely fit 5 cards across two rows */
.tech__card:nth-child(1){ grid-column:span 2; }
.tech__card:nth-child(2){ grid-column:span 1; }
.tech__card:nth-child(3){ grid-column:span 1; }
.tech__card:nth-child(4){ grid-column:span 2; }
.tech__card:nth-child(5){ grid-column:span 2; }

/* ============================================================
   Prices
   ============================================================ */
.prices{ display:grid; grid-template-columns:repeat(3,1fr); gap:18px; align-items:stretch; }
/* Bottom row: 3 cards centered in 3-col grid */
.prices .price:nth-child(4){ grid-column:1; }
.prices .price:nth-child(5){ grid-column:2; }
.prices .price:nth-child(6){ grid-column:3; }
.price{
  position:relative; display:flex; flex-direction:column;
  padding:32px 28px; border-radius:var(--radius-lg);
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s, box-shadow .4s;
}
.price:hover{ transform:translateY(-6px); border-color:var(--line); box-shadow:var(--shadow); }
.price--feat{ background:linear-gradient(180deg,#0f1a18,var(--surface)); border-color:var(--line); }
.price__flag{ position:absolute; top:-11px; right:20px; padding:6px 13px; border-radius:999px; font-size:.68rem; font-weight:700; text-transform:uppercase; letter-spacing:.1em; color:#04130f; background:var(--grad); box-shadow:0 8px 18px -8px rgba(0,0,0,.7); }
.price__name{ font-family:var(--font-disp); font-weight:600; font-size:1.15rem; color:var(--text-2); margin-bottom:14px; min-height:2.6em; }
.price__big{ font-family:var(--font-disp); font-weight:700; font-size:2.8rem; letter-spacing:-.03em; line-height:1; margin-bottom:24px; }
.price__big small{ font-size:1rem; font-weight:500; color:var(--text-3); letter-spacing:0; }
.price__list{ display:grid; gap:12px; margin-bottom:28px; }
.price__list li{ display:flex; align-items:center; gap:11px; font-size:.98rem; color:var(--text-2); }
.price__list .ic{ font-size:1.05rem; color:var(--acc); stroke-width:2.4; flex-shrink:0; }
/* Ultra Duo card */
.price--ultra{
  background:linear-gradient(160deg, #0f1a18, var(--bg-2));
  border-color:rgba(27,186,152,.35);
}
.price--ultra .price__flag{ background:var(--grad); }

/* PlayStation card */
.price--ps{
  background:linear-gradient(160deg, #0d1620, var(--bg-2));
  border-color:rgba(0,120,215,.3);
}
.price--ps .price__big{ color:#58a6ff; }
.price--ps .price__list .ic{ color:#58a6ff; }

.prices__hint{ display:flex; align-items:center; gap:10px; justify-content:center; margin-top:26px; color:var(--text-3); font-size:.92rem; text-align:center; }
.prices__hint .ic{ font-size:1.2rem; color:var(--acc); flex-shrink:0; }

/* ============================================================
   CTA band
   ============================================================ */
.cta{ position:relative; }
.cta__inner{
  position:relative; overflow:hidden;
  padding:clamp(40px,6vw,72px); border-radius:var(--radius-lg); text-align:center;
  background:linear-gradient(135deg, rgba(0,212,167,.14), rgba(13,15,18,.6)), var(--surface);
  border:1px solid var(--line);
  box-shadow:var(--glow);
}
.cta__inner::before{ content:""; position:absolute; inset:0; background-image:linear-gradient(rgba(27,186,152,.08) 1px,transparent 1px),linear-gradient(90deg,rgba(27,186,152,.08) 1px,transparent 1px); background-size:40px 40px; -webkit-mask-image:radial-gradient(60% 60% at 50% 50%,#000,transparent); mask-image:radial-gradient(60% 60% at 50% 50%,#000,transparent); }
.cta__title{ position:relative; font-family:var(--font-disp); font-weight:700; font-size:clamp(2.2rem,5vw,3.6rem); letter-spacing:-.025em; margin-bottom:12px; }
.cta p{ position:relative; color:var(--text-2); max-width:520px; margin:0 auto 30px; }
.cta__actions{ position:relative; display:flex; flex-wrap:wrap; gap:14px; justify-content:center; }

/* ============================================================
   Contacts
   ============================================================ */
.contacts{ display:grid; grid-template-columns:1fr 1fr; gap:34px; align-items:center; }
.contacts__list{ display:grid; gap:6px; margin:30px 0 26px; }
.contacts__list li{ display:flex; align-items:flex-start; gap:16px; padding:16px 0; border-top:1px solid var(--line-2); }
.contacts__list .ic{ font-size:1.4rem; color:var(--acc); margin-top:3px; }
.contacts__list span{ display:block; font-size:.74rem; text-transform:uppercase; letter-spacing:.1em; color:var(--text-3); margin-bottom:3px; }
.contacts__list a{ font-weight:600; font-size:1.05rem; transition:color .25s; }
.contacts__list a:hover{ color:var(--acc-3); }
.contacts__socials{ display:flex; flex-wrap:wrap; gap:12px; }
.soc{ padding:11px 20px; border-radius:999px; border:1px solid var(--line); font-weight:600; font-size:.92rem; color:var(--text); transition:.25s var(--ease); }
.soc:hover{ background:rgba(27,186,152,.1); border-color:var(--acc); color:var(--acc-3); transform:translateY(-2px); }

.contacts__map{
  position:relative; aspect-ratio:1.25/1; border-radius:var(--radius-lg); overflow:hidden;
  background:radial-gradient(120% 120% at 70% 20%, #0f1a18, var(--bg-2));
  border:1px solid var(--line); display:grid; place-items:center;
  transition:transform .4s var(--ease), box-shadow .4s;
}
.contacts__map:hover{ box-shadow:var(--shadow); }
.map__grid{ position:absolute; inset:0; background-image:linear-gradient(rgba(27,186,152,.12) 1px,transparent 1px),linear-gradient(90deg,rgba(27,186,152,.12) 1px,transparent 1px); background-size:34px 34px; }
.map__pin{ position:relative; display:grid; place-items:center; width:74px; height:74px; border-radius:50%; background:rgba(27,186,152,.12); border:1px solid var(--acc); animation:ping 2.4s var(--ease) infinite; }
.map__pin .ic{ font-size:2rem; color:var(--acc-3); }
@keyframes ping{ 0%{ box-shadow:0 0 0 0 rgba(27,186,152,.45);} 70%,100%{ box-shadow:0 0 0 28px rgba(27,186,152,0);} }
.map__cta{ position:absolute; bottom:18px; left:18px; right:18px; display:flex; align-items:center; justify-content:center; gap:8px; padding:12px; border-radius:14px; background:rgba(10,11,13,.7); backdrop-filter:blur(8px); border:1px solid var(--line-2); font-weight:600; font-size:.92rem; }
.map__cta .ic{ color:var(--acc-3); }

/* ============================================================
   Footer
   ============================================================ */
.footer{ border-top:1px solid var(--line-2); padding:36px 0; }
.footer__inner{ display:flex; align-items:center; gap:24px; flex-wrap:wrap; justify-content:space-between; }
.logo--footer .logo__mark{ font-size:1.3rem; }
.footer__copy{ color:var(--text-3); font-size:.88rem; }
.footer__nav{ display:flex; gap:18px; }
.footer__nav a{ color:var(--text-2); font-size:.9rem; font-weight:600; transition:color .25s; }
.footer__nav a:hover{ color:var(--acc-3); }

/* ============================================================
   Reveal animation
   ============================================================ */
.reveal{ opacity:0; transform:translateY(28px); transition:opacity .8s var(--ease), transform .8s var(--ease); }
.reveal.is-in{ opacity:1; transform:none; }

