file.content:
.mob-banner{
  display:none; /* hidden on desktop */
  position:relative;
  width:100%;
  border-radius:24px;
  overflow:hidden;
  padding:48px 24px 32px;
  flex-direction:column;
  align-items:center;
  text-align:center;
  gap:0;
  isolation:isolate;
}
.mob-banner__bg{
  position:absolute; inset:0;
  background:radial-gradient(ellipse at 50% 30%, rgba(27,186,152,.18) 0%, rgba(10,11,13,.95) 65%);
  z-index:0;
}
.mob-banner__glow{
  position:absolute;
  top:-40px; left:50%; transform:translateX(-50%);
  width:260px; height:260px;
  background:radial-gradient(circle, rgba(27,186,152,.32) 0%, transparent 70%);
  border-radius:50%;
  z-index:0;
  animation:mobGlow 4s ease-in-out infinite;
}
@keyframes mobGlow{
  0%,100%{ opacity:.7; transform:translateX(-50%) scale(1); }
  50%{ opacity:1; transform:translateX(-50%) scale(1.15); }
}
.mob-banner__content{
  position:relative; z-index:1;
  display:flex; flex-direction:column; align-items:center; gap:8px;
  margin-bottom:32px;
}
.mob-banner__label{
  font-size:.65rem; letter-spacing:.45em; text-transform:uppercase;
  color:var(--acc-3); margin-bottom:4px;
}
.mob-banner__logo{
  font-family:var(--font-disp); font-weight:700;
  font-size:clamp(4.5rem, 22vw, 6rem);
  line-height:1; letter-spacing:-.04em;
  color:#fff;
  text-shadow:0 0 60px rgba(27,186,152,.5);
}
.mob-banner__logo span{
  color:var(--acc-3);
  display:inline-block; margin-right:0.04em;
}
.mob-banner__sub{
  font-size:.8rem; color:var(--text-3); letter-spacing:.06em;
  margin-top:6px;
}
.mob-banner__chips{
  position:relative; z-index:1;
  display:flex; flex-wrap:wrap; justify-content:center; gap:8px;
  width:100%;
}
.mob-banner__chip{
  display:inline-flex; align-items:center; gap:6px;
  background:rgba(27,186,152,.1);
  border:1px solid rgba(27,186,152,.25);
  border-radius:20px;
  padding:6px 12px;
  font-size:.72rem; font-weight:600;
  color:var(--text-2);
  backdrop-filter:blur(6px);
}
.mob-banner__chip .ic{ color:var(--acc-3); width:13px; height:13px; }


/* On desktop the flex chip rows are hidden — chips float absolutely inside orb */
.orb__chips-top, .orb__chips-bottom{ display:none; }
@media (max-width:1024px){
  .hero__inner{ grid-template-columns:1fr; gap:40px; }
  .hero__visual{ order:-1; }
  .orb{ width:min(340px,70vw); }
  .zones{ grid-template-columns:repeat(2,1fr); }
  .zone{ grid-column:span 1; }
  .tech{ grid-template-columns:repeat(2,1fr); }
  .tech__card,.tech__card:nth-child(n){ grid-column:span 1; }
  .tech__card--wide:first-child{ grid-column:span 2; }
}
@media (max-width:780px){
  .nav, .header__cta{ display:none; }
  .burger{ display:flex; }
  .prices{ grid-template-columns:1fr 1fr; gap:14px; }
  /* reset explicit column positions on mobile */
  .prices .price:nth-child(n){ grid-column:auto; }
  /* PlayStation card full-width on 2-col */
  .prices .price--ps{ grid-column:span 2; }
  .contacts{ grid-template-columns:1fr; }
  .hero{ padding-top:110px; min-height:auto; }
  .hero__stats{ grid-template-columns:repeat(2,1fr); gap:18px 14px; }
  .cursor{ display:none !important; }
  body.cursor-on{ cursor:auto; }
}
@media (max-width:560px){
  .zones{ grid-template-columns:1fr; }
  .tech{ grid-template-columns:1fr; }
  .tech__card--wide:first-child{ grid-column:span 1; }
  .specs li{ grid-template-columns:auto 92px 1fr; gap:10px; font-size:.86rem; }
  .section__head{ margin-bottom:36px; }
  .footer__inner{ flex-direction:column; text-align:center; }

  /* Hide orb, show mobile banner */
  .orb{ display:none !important; }
  .mob-banner{ display:flex; }

  /* Prices: single column, compact cards */
  .prices{ grid-template-columns:1fr; gap:12px; }
  .prices .price--ps{ grid-column:auto; }
  .price{ padding:22px 18px; }
  .price__name{ font-size:1rem; min-height:auto; margin-bottom:10px; }
  .price__big{ font-size:2.2rem; margin-bottom:16px; }
  .price__list{ gap:9px; margin-bottom:20px; }
  .price__list li{ font-size:.9rem; }
}

/* pointer-fine devices show the custom cursor */
