404	  position:relative; aspect-ratio:1.25/1; border-radius:var(--radius-lg); overflow:hidden;
405	  background:radial-gradient(120% 120% at 70% 20%, #0f1a18, var(--bg-2));
406	  border:1px solid var(--line); display:grid; place-items:center;
407	  transition:transform .4s var(--ease), box-shadow .4s;
408	}
409	.contacts__map:hover{ box-shadow:var(--shadow); }
410	.map__frame{ position:absolute; inset:0; width:100%; height:100%; border:0; }
411	.map__grid{ position:absolute; inset:0; background-image:linear-gradient(rgba(27,186,152,.12) 1px,transparent 1px),linear-gradient(90deg,rgba(27,186,152,.12) 1px,transparent 1px); background-size:34px 34px; }
412	.map__pin{ position:relative; display:grid; place-items:center; width:74px; height:74px; border-radius:50%; background:rgba(27,186,152,.12); border:1px solid var(--acc); animation:ping 2.4s var(--ease) infinite; }
413	.map__pin .ic{ font-size:2rem; color:var(--acc-3); }
414	@keyframes ping{ 0%{ box-shadow:0 0 0 0 rgba(27,186,152,.45);} 70%,100%{ box-shadow:0 0 0 28px rgba(27,186,152,0);} }
415	.map__cta{ position:absolute; bottom:18px; left:18px; right:18px; display:flex; align-items:center; justify-content:center; gap:8px; padding:12px; border-radius:14px; background:rgba(10,11,13,.7); backdrop-filter:blur(8px); border:1px solid var(--line-2); font-weight:600; font-size:.92rem; }
416	.map__cta .ic{ color:var(--acc-3); }
417	
418	/* ============================================================
419	   Footer
420	   ============================================================ */
421	.footer{ border-top:1px solid var(--line-2); padding:36px 0; }
422	.footer__inner{ display:flex; align-items:center; gap:24px; flex-wrap:wrap; justify-content:space-between; }
423	.logo--footer .logo__mark{ font-size:1.3rem; }
424	.footer__copy{ color:var(--text-3); font-size:.88rem; }
425	.footer__nav{ display:flex; gap:18px; }
426	.footer__nav a{ color:var(--text-2); font-size:.9rem; font-weight:600; transition:color .25s; }
427	.footer__nav a:hover{ color:var(--acc-3); }
428	
429	/* ============================================================
430	   Reveal animation
431	   ============================================================ */
432	.reveal{ opacity:0; transform:translateY(28px); transition:opacity .8s var(--ease), transform .8s var(--ease); }
433	.reveal.is-in{ opacity:1; transform:none; }
434	
435	/* ============================================================
436	   Responsive
437	   ============================================================ */
438	@media (max-width:1024px){
439	  .hero__inner{ grid-template-columns:1fr; gap:40px; }
440	  .hero__visual{ order:-1; }
441	  .orb{ width:min(340px,70vw); }
442	  .zones{ grid-template-columns:repeat(2,1fr); }
443	  .zone{ grid-column:span 1; }
444	  .tech{ grid-template-columns:repeat(2,1fr); }
445	  .tech__card,.tech__card:nth-child(n){ grid-column:span 1; }
446	  .tech__card--wide:first-child{ grid-column:span 2; }
447	}
448	@media (max-width:780px){
449	  .nav, .header__cta{ display:none; }
450	  .burger{ display:flex; }
451	  .price{ max-width:none; flex-basis:100%; }
452	  .contacts{ grid-template-columns:1fr; }
453	  .hero{ padding-top:110px; min-height:auto; }
454	  .hero__stats{ grid-template-columns:repeat(2,1fr); gap:18px 14px; }
455	  .cursor{ display:none !important; }
456	  body.cursor-on{ cursor:auto; }
457	}
458	@media (max-width:560px){
459	  .zones{ grid-template-columns:1fr; }
460	  .tech{ grid-template-columns:1fr; }
461	  .tech__card--wide:first-child{ grid-column:span 1; }
462	  .specs li{ grid-template-columns:auto 92px 1fr; gap:10px; font-size:.86rem; }
463	  .section__head{ margin-bottom:36px; }
464	  .footer__inner{ flex-direction:column; text-align:center; }
465	}
466	
467	/* pointer-fine devices show the custom cursor */
468	@media (hover:hover) and (pointer:fine){ .cursor{ display:block; } }
469	
470	@media (prefers-reduced-motion:reduce){
471	  *{ animation-duration:.001ms !important; animation-iteration-count:1 !important; transition-duration:.001ms !important; scroll-behavior:auto !important; }
472	  .reveal{ opacity:1; transform:none; }
473	}
