   ============================================================ */
.prices{ display:flex; flex-wrap:wrap; justify-content:center; gap:18px; align-items:stretch; }
.price{
  position:relative; display:flex; flex-direction:column;
  flex:1 1 300px; max-width:384px;
  padding:32px 28px; border-radius:var(--radius-lg);
