   ============================================================ */
.benefits{ display:grid; grid-template-columns:repeat(3,1fr); gap:18px; }
.benefit{
  display:flex; flex-direction:column; gap:14px;
  padding:28px; border-radius:var(--radius);
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s, box-shadow .4s;
}
.benefit:hover{ transform:translateY(-4px); border-color:var(--line); box-shadow:var(--shadow); }
.benefit__ic{
  width:46px; height:46px; border-radius:13px;
  background:rgba(27,186,152,.1); border:1px solid var(--line);
  display:grid; place-items:center; flex-shrink:0;
}
.benefit__ic .ic{ width:22px; height:22px; stroke:var(--acc-3); }
.benefit h3{ font-family:var(--font-disp); font-weight:700; font-size:1.08rem; margin-bottom:4px; }
.benefit p{ color:var(--text-2); font-size:.9rem; line-height:1.55; }

/* ============================================================
   Reviews / Social proof
   ============================================================ */
.reviews{ display:grid; grid-template-columns:repeat(3,1fr); gap:18px; }
.review{
  display:flex; flex-direction:column; gap:14px;
  padding:28px; border-radius:var(--radius-lg);
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s;
}
.review:hover{ transform:translateY(-4px); border-color:var(--line); }
.review__stars{ color:var(--acc-3); font-size:1rem; letter-spacing:2px; }
.review__text{ color:var(--text-2); font-size:.95rem; line-height:1.65; flex:1; }
.review__author{ display:flex; align-items:center; gap:12px; padding-top:16px; border-top:1px solid var(--line-2); }
.review__avatar{
  width:42px; height:42px; border-radius:50%; flex-shrink:0;
  background:var(--grad); display:grid; place-items:center;
  font-family:var(--font-disp); font-weight:700; font-size:1rem; color:#04130f;
}
.review__name{ font-weight:700; font-size:.95rem; line-height:1.2; }
.review__meta{ font-size:.76rem; color:var(--text-3); margin-top:2px; }
.reviews-stat{
  display:flex; align-items:center; justify-content:center; gap:0; flex-wrap:wrap;
  margin-bottom:42px; border-radius:var(--radius);
  background:var(--surface); border:1px solid var(--line-2); overflow:hidden;
}
.reviews-stat__item{
  display:flex; flex-direction:column; align-items:center; gap:4px;
  padding:22px 36px; flex:1; min-width:140px;
  border-right:1px solid var(--line-2);
}
.reviews-stat__item:last-child{ border-right:none; }
.reviews-stat__num{ font-family:var(--font-disp); font-weight:700; font-size:2rem; line-height:1; color:var(--text); }
.reviews-stat__num em{ font-style:normal; color:var(--acc-3); }
.reviews-stat__label{ font-size:.74rem; color:var(--text-3); text-transform:uppercase; letter-spacing:.1em; text-align:center; }

/* ============================================================
   FAQ
   ============================================================ */
.faq{ display:grid; gap:10px; max-width:780px; margin:0 auto; }
.faq__item{
  border-radius:var(--radius); background:var(--surface); border:1px solid var(--line-2);
  overflow:hidden; transition:border-color .3s;
}
.faq__item[open]{ border-color:var(--line); }
.faq__item summary{
  display:flex; align-items:center; justify-content:space-between; gap:16px;
  padding:20px 24px; cursor:pointer; list-style:none;
  font-family:var(--font-disp); font-weight:600; font-size:1rem;
  user-select:none; transition:color .25s;
}
.faq__item summary::-webkit-details-marker{ display:none; }
.faq__item summary:hover{ color:var(--acc-3); }
.faq__ic{ width:20px; height:20px; flex-shrink:0; fill:none; stroke:var(--acc); stroke-width:2.2; transition:transform .3s var(--ease); }
.faq__item[open] summary .faq__ic{ transform:rotate(45deg); }
.faq__item > div{ padding:0 24px 20px; color:var(--text-2); font-size:.95rem; line-height:1.65; }
.section--faq .section__head{ margin-inline:auto; text-align:center; }
.prices__note{
  display:flex; align-items:center; justify-content:center; gap:8px;
  margin-top:28px; color:var(--text-3); font-size:.88rem; text-align:center;
}
.prices__note .ic{ color:var(--acc); font-size:1.1rem; flex-shrink:0; }

