/* ============================================================
   Hero promo hook
   ============================================================ */
.hero__promo{
  display:inline-flex; align-items:center; gap:10px;
  margin:0 0 22px; padding:8px 16px 8px 9px;
  border-radius:999px; background:rgba(27,186,152,.08);
  border:1px solid var(--line); font-size:.92rem; font-weight:600;
}
.hero__promo b{ color:var(--acc-3); font-weight:700; }
.hero__promo .tag{
  font-family:var(--font-disp); font-size:.64rem; font-weight:700;
  letter-spacing:.1em; text-transform:uppercase; color:#04130f;
  background:var(--grad); padding:4px 10px; border-radius:999px;
}

/* ============================================================
   Offers / Акции
   ============================================================ */
.section--offers{ background:linear-gradient(var(--bg),var(--bg-2)); }
.offers{ display:grid; grid-template-columns:repeat(3,1fr); gap:18px; }
.offer{
  position:relative; display:flex; flex-direction:column; gap:14px;
  padding:30px 28px; border-radius:var(--radius-lg); overflow:hidden;
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s, box-shadow .4s;
}
.offer::after{ content:""; position:absolute; width:220px; height:220px; border-radius:50%; top:-100px; right:-100px; background:radial-gradient(circle, rgba(27,186,152,.18), transparent 70%); opacity:0; transition:opacity .4s; pointer-events:none; }
.offer:hover{ transform:translateY(-6px); border-color:var(--line); box-shadow:var(--shadow); }
.offer:hover::after{ opacity:1; }
.offer--feat{ background:linear-gradient(160deg,#0f1a18,var(--surface)); border-color:var(--line); }
.offer__badge{
  align-self:flex-start; display:inline-flex; align-items:center; gap:6px;
  font-family:var(--font-disp); font-size:.64rem; font-weight:700;
  letter-spacing:.1em; text-transform:uppercase; color:var(--acc-3);
  background:rgba(27,186,152,.1); border:1px solid var(--line);
  padding:5px 11px; border-radius:999px;
}
.offer__ic{ width:38px; height:38px; stroke:var(--acc); fill:none; stroke-width:1.6; filter:drop-shadow(0 0 10px rgba(27,186,152,.5)); }
.offer__big{ font-family:var(--font-disp); font-weight:700; font-size:2.1rem; line-height:1; letter-spacing:-.02em; }
.offer__big span{ font-size:1rem; color:var(--text-3); font-weight:500; }
.offer h3{ font-family:var(--font-disp); font-weight:700; font-size:1.18rem; }
.offer p{ color:var(--text-2); font-size:.92rem; line-height:1.55; flex:1; }
.offer__note{ display:flex; align-items:center; gap:7px; font-size:.78rem; color:var(--text-3); }
.offer__note .ic{ color:var(--acc); font-size:.95rem; flex-shrink:0; }

/* ============================================================
   How to book — steps
   ============================================================ */
.steps{ display:grid; grid-template-columns:repeat(3,1fr); gap:18px; }
.step{
  position:relative; padding:30px 28px; border-radius:var(--radius-lg);
  background:var(--surface); border:1px solid var(--line-2);
  transition:transform .4s var(--ease), border-color .4s;
}
.step:hover{ transform:translateY(-4px); border-color:var(--line); }
.step__num{
  display:grid; place-items:center; width:52px; height:52px; margin-bottom:18px;
  border-radius:50%; background:var(--grad-soft); border:1px solid var(--line);
  font-family:var(--font-disp); font-weight:700; font-size:1.4rem; color:var(--acc-3);
}
.step h3{ font-family:var(--font-disp); font-weight:700; font-size:1.2rem; margin-bottom:8px; }
.step p{ color:var(--text-2); font-size:.92rem; line-height:1.55; }
.step:not(:last-child)::after{
  content:""; position:absolute; top:55px; right:-10px; width:20px; height:2px;
  background:var(--line); z-index:1;
}
.steps__cta{ display:flex; justify-content:center; margin-top:36px; }

/* ============================================================
   Sticky mobile action bar
   ============================================================ */
.mobile-bar{
  display:none; position:fixed; left:0; right:0; bottom:0; z-index:880;
  gap:10px; padding:12px 16px calc(12px + env(safe-area-inset-bottom));
  background:rgba(10,11,13,.92); backdrop-filter:blur(16px); -webkit-backdrop-filter:blur(16px);
  border-top:1px solid var(--line-2);
}
.mobile-bar .btn{ flex:1; justify-content:center; }

/* ============================================================
   Floating WhatsApp
   ============================================================ */
.fab{
  position:fixed; right:24px; bottom:24px; z-index:870;
  width:58px; height:58px; border-radius:50%;
  display:grid; place-items:center; background:var(--grad); color:#04130f;
  box-shadow:0 12px 30px -8px rgba(27,186,152,.7);
  transition:transform .3s var(--ease), box-shadow .3s;
  animation:fabPulse 2.8s var(--ease) infinite;
}
.fab:hover{ transform:scale(1.08); box-shadow:0 16px 38px -8px rgba(27,186,152,.9); }
.fab .ic{ width:26px; height:26px; stroke-width:1.9; }
@keyframes fabPulse{
  0%,100%{ box-shadow:0 12px 30px -8px rgba(27,186,152,.7), 0 0 0 0 rgba(27,186,152,.45); }
  70%{ box-shadow:0 12px 30px -8px rgba(27,186,152,.7), 0 0 0 16px rgba(27,186,152,0); }
}

